        start_zone = 'Altepa',
        start_pos = nil,
        description = 'Upgrading the fuel capacity of the martellos in the Altepa Desert will mean less frequent replenishment runs, easing the burden on Resistance troops in the area. Install a fuel reservoir in a martello, and return the excess parts to the machine outfitter when the job is done.',
