        start_npc = 'Resistance Sapper, Abyssea',
        start_zone = 'Attohwa',
        start_pos = 'I-9',
        description = 'Enfeeblement traps have been laid along the outpost\'s perimeter in order to weaken would-be besiegers. This operation requires you to infuse a rear trap with paralysis trap fluid, its energy source. Be mindful of your distance from the trap when performing the infusion.',
