        start_npc = 'Resistance Sapper, Abyssea',
        start_zone = 'Attohwa',
        start_pos = 'F-9',
        description = 'The continual defense of the pulse martello has pushed our soldiers to the brink of exhaustion. This operation requires you to transport ensorceled battle provisions from the stockpile, using the enchanted sack provided. Be mindful that the sack does not rupture in the process.',
