    ['Dropping the Bomb'] = {
        id = 55,
        start_npc = 'Veit (A), Abyssea',
        start_zone = 'Misareaux',
        start_pos = nil,
        description = 'Caskets containing gunpowder intended for a critical blasting operation have been lost in transit. With his soldiers apparently a bunch of hopeless cravens, Veit requires that you retrieve the caskets, which were last seen being dumped into the river.',
        reward = '1,200 Cruor\nVersa Breeches with random  Augments',
        fame = 'Abyssea',
        fame_level = '3',
        title = nil,
        repeatable = 'Yes',
        previous = nil,
        next = nil,
        requirements = {
            {name = 'Powder Casket', count = 1},
        },
        walkthrough = '1. Speak to Veit (A) at (H-4). He is northeast of Conflux #5.\n2. He will request a Powder Casket. These can be obtained by defeating Brine Crab, which are fished up in the nearby stream.\n   - To fish up the Brine Crab almost any pole/bait combination works. The crabs will have the "ferociously bites" message.\n   - The drop rate is  from the brine crab. Treasure Hunter is strongly encouraged.\n3. After obtaining the Powder Casket, trade it back to Veit (A).\n4. There is a chance he will not accept the casket because it has "moisture" inside. You will have to obtain another casket.\n5. After you trade an acceptable casket, you will complete the quest.\n6. The Versa Breeches will have a random  on them.\nZoning is required to repeat this quest.',
        notes = nil,
    },
