        start_npc = 'Guilboire (A), Abyssea',
        start_zone = 'Uleguerand',
        start_pos = nil,
        description = 'Following in the footsteps of his Crystal War veteran father, the enterprising Guilboire seeks to harness the power of snolls to strike back at the hordes. Travel to the test site and assist with data collection.',
        reward = '10~600 Cruor for each completion, depending on the damage dealt from the explosion.\nChance at one of the following:\nBloody Bolt x10\nAcid Bolt x10\nSnoll Gelato\nChance of one of the following:\nBale Seal: Hands (DRK)\nMavi Seal: Hands (BLU)\nCaller\'s Seal: Hands (SMN)\nGoetia Seal: Hands (BLM)',
        fame = 'Abyssea',
