    ['Slip Slidin\' Away'] = {
        id = 76,
        start_npc = 'Michilca (A), Abyssea',
        start_zone = 'Uleguerand',
        start_pos = nil,
        description = 'The Resistance seeks to send a strike team into the bowels of Thousandfall Ridge, a confirmed breeding pit for the hordes. Help keep Michilca\'s men on course as they execute their hazardous approach.',
        reward = 'Resilient Mantle \nChance at one of the following Empyrean Armor +1 Hands seals:\nAoidos\' Seal: Hands\nEstoqueur\'s Seal: Hands\nRaider\'s Seal: Hands\nSavant\'s Seal: Hands',
        fame = 'Abyssea',
        fame_level = '2',
        title = nil,
        repeatable = 'Yes',
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Michilca (A) is at the base camp. Talk to her to begin.\n2. Head to Conflux #7, and continue south past the Surveyors.\n3. Head towards the western cliff near the gears.\n4. You must start falling down the cliff at approximately 1/3 of the distance from the north wall and begin falling down.\n   - Zoom your camera completely out, then angle it downwards and left or right to see as far down the cliff as possible. You want to aim for the very small dip in the terrain, as just below that is the hole you must fall into.\n   - If you "run backwards" up the cliff while you are sliding it slightly helps slow you down so you can hit the spot.\n5. After meeting your mark, you need to speak to Perfaumand (A) right inside the entrance.\n6. After speaking to him, NPCs will begin falling down the cliff. Your goal is to target each one, and "talk" or examine them to make them stop falling and slide towards the cliff.\n   - Wobble left and right depending on what side the NPCs are falling, but be careful not to fall off yourself.\n   - There will be 3 waves of 2-3 NPCs in each wave.\n   - Position your camera and your character like the image below. Even if the NPCs fall past you, but you interact with the in time, they will still be saved.\n7. After the NPCs stop falling, you MUST speak with Perfaumand (A) before leaving the area.\n8. The closest conflux (Conflux #2) is off the edge, past the imps and into the tunnel.\n9. Report to Michilca (A) to complete this quest.\nZoning is required in order to repeat this quest.\ncfq3HwXRWhI',
        notes = nil,
