    ['The Soul of the Matter'] = {
        id = 17,
        start_npc = 'Cleades, Abyssea',
        start_zone = 'Konschtat',
        start_pos = 'G-5',
        description = 'A reconnaissance expert has taken you under his wing to tutor you in the arcane art of soulgauging. Venture afield with your Soulgauger SGR-1 and collect intelligence on the notorious fiends aprowl in the vicinity.',
        reward = 'First time completion:\n400~520 Cruor\nBehemoth Ring  \nSubsequent completions:\n200~260 Cruor',
